const connectSocket = (loginName, socketIp) => {
  const socketUrl = `${socketIp || "http://192.168.0.202:7777"}?connectId=${loginName}_lxtQuestion`;
  console.log("socketUrl", socketUrl);
  const socketParams = { path: "/znxlsocketio" };
  return io(socketUrl, socketParams);
};

const useSocket = () => {
  const socket = ref();
  const initMsgInfo = { question: "", type: "" };
  const receivedMsgInfo = ref({ ...initMsgInfo });
  const connectSocketIo = (loginName, socketIp) => {
    socket.value = connectSocket(loginName, socketIp);
    socket.value.on("connect", () => {
      console.log("连接鹿小图socket成功");
    });
    socket.value.on("lxtMessage", (data) => {
      console.log("接收到鹿小图消息", data);
      data && (receivedMsgInfo.value = data);
    });
    socket.value.on("connect_error", (err) => {
      console.error("鹿小图socket连接失败：", err);
    });
  };
  return {
    socket,
    receivedMsgInfo,
    connectSocketIo
  };
};

const useCardMsg = (msgInfo) => {
  const isShowTipCard = ref(false);
  const msgText = ref("");
  const msgState = ref("");
  const resetCardState = () => {
    isShowTipCard.value = false;
    msgText.value = "";
    msgState.value = "";
  };
  watch(msgInfo, (info) => {
    const { question, type } = info;
    console.log(info, "msgInfo");
    if (type === "wake" || type === "search") {
      isShowTipCard.value = true;
    }
    msgText.value = question;
    msgState.value = type;
    if (type === "finish") {
      setTimeout(() => {
        resetCardState();
      }, 2e3);
    }
    if (type === "sleep") {
      resetCardState();
    }
  });
  return {
    isShowTipCard,
    msgText,
    msgState,
    resetCardState
  };
};

